class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        bracket_pairs = {')': '(', '}': '{', ']': '['}
        for char in s:
            if char in bracket_pairs.values():
                stack.append(char)
            elif char in bracket_pairs.keys():
                if stack and stack[-1] == bracket_pairs[char]:
                    stack.pop()
                else:
                    return False
            else:
                return False
        return len(stack) == 0
